import Link from "next/link";

import { EnrichmentPendingRefresh } from "@/features/enrichment/components/pending-refresh";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import { searchOwnerContent } from "@/features/search/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

type SearchPageProps = {
  searchParams?: Promise<{
    q?: string;
  }>;
};

export default async function SearchPage({ searchParams }: SearchPageProps) {
  const owner = await requireOwnerSession();
  const resolvedSearchParams = (await searchParams) ?? {};
  const results = await searchOwnerContent(owner.id, resolvedSearchParams.q);
  const resultCount = results.notes.length + results.links.length;
  const hasPendingResults =
    results.notes.some((note) => note.enrichment.status === "pending") ||
    results.links.some((link) => link.enrichment.status === "pending");

  return (
    <div className="feature-layout">
      <EnrichmentPendingRefresh enabled={hasPendingResults} />
      <section className="hero-card">
        <p className="eyebrow">Owner search</p>
        <h1>Search private titles, URLs, and tags.</h1>
        <p className="lede">
          This search stays inside the owner area. Public readers do not get a search interface in v1.
        </p>
        <div className="summary-row">
          <div>
            <strong>Scope</strong>
            <span>Titles, URLs, and shared tag names</span>
          </div>
          <div>
            <strong>Body search</strong>
            <span>Note bodies and link summaries stay out of scope in v1</span>
          </div>
          <div>
            <strong>Current results</strong>
            <span>{results.query ? `${resultCount} match${resultCount === 1 ? "" : "es"}` : "Run a query to inspect the vault"}</span>
          </div>
        </div>
      </section>

      <form action="/app/search" className="panel-card search-form" role="search">
        <div className="section-heading">
          <strong>Search the private vault</strong>
          <span className="section-meta">Owner-only retrieval</span>
        </div>
        <label className="field-group">
          <span>Query</span>
          <input
            autoComplete="off"
            className="text-input"
            defaultValue={results.query}
            name="q"
            placeholder="Search note titles, link titles, URLs, or tags"
            type="search"
          />
        </label>
        <div className="button-row">
          <button className="primary-button" type="submit">
            Search
          </button>
        </div>
      </form>

      {results.query ? (
        <div className="retrieval-grid">
          <section className="panel-card">
            <div className="section-heading">
              <strong>Matching notes</strong>
              <span className="section-meta">{results.notes.length} result{results.notes.length === 1 ? "" : "s"}</span>
            </div>
            {results.notes.length === 0 ? (
              <p>No private notes matched this query.</p>
            ) : (
              <div className="note-list">
                {results.notes.map((note) => (
                  <article className="note-list-item" key={note.id}>
                    <div>
                      <div className="note-meta note-meta-leading">
                        <span>{note.isPublished ? "Published" : "Draft"}</span>
                        <span>{new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(note.updatedAt)}</span>
                      </div>
                      <Link className="note-list-link" href={`/app/notes/${note.id}/edit`}>
                        {note.title}
                      </Link>
                      <p>{note.excerpt || "Empty draft"}</p>
                      {note.summary ? <p className="note-generated-summary">AI summary: {note.summary}</p> : null}
                      <EnrichmentStatusBlock state={note.enrichment} />
                      <div className="tag-list" aria-label="Note tags">
                        {note.tags.length === 0 ? (
                          <span className="tag-pill tag-pill-muted">Untagged</span>
                        ) : (
                          note.tags.map((tag) => (
                            <span className="tag-pill" key={tag.id}>
                              {tag.name}
                            </span>
                          ))
                        )}
                      </div>
                    </div>
                  </article>
                ))}
              </div>
            )}
          </section>

          <section className="panel-card">
            <div className="section-heading">
              <strong>Matching links</strong>
              <span className="section-meta">{results.links.length} result{results.links.length === 1 ? "" : "s"}</span>
            </div>
            {results.links.length === 0 ? (
              <p>No private links matched this query.</p>
            ) : (
              <div className="link-list">
                {results.links.map((link) => (
                  <article className="link-list-item" key={link.id}>
                    <div className="link-list-heading">
                      <div className="note-meta note-meta-leading">
                        <span>Private link</span>
                      </div>
                      <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                        {link.title}
                      </a>
                      <p className="link-url">{link.url}</p>
                    </div>
                    {link.summary ? <p className="link-summary">AI summary: {link.summary}</p> : null}
                    <EnrichmentStatusBlock state={link.enrichment} />
                    <div className="link-list-footer">
                      <div className="tag-list" aria-label="Link tags">
                        {link.tags.length === 0 ? (
                          <span className="tag-pill tag-pill-muted">No generated tags yet</span>
                        ) : (
                          link.tags.map((tag) => (
                            <span className="tag-pill" key={tag.id}>
                              {tag.name}
                            </span>
                          ))
                        )}
                      </div>
                      <div className="note-meta">
                        <span>Updated</span>
                        <span>{new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(link.updatedAt)}</span>
                      </div>
                    </div>
                  </article>
                ))}
              </div>
            )}
          </section>
        </div>
      ) : (
        <section className="panel-card">
          <div className="section-heading">
            <strong>Search scope</strong>
            <span className="section-meta">v1 boundaries</span>
          </div>
          <p>Search matches note titles, link titles, link URLs, and shared tag names. Note bodies and link summaries stay out of scope in v1.</p>
        </section>
      )}
    </div>
  );
}

"use client";

import { useEffect } from "react";
import { useRouter } from "next/navigation";

type EnrichmentPendingRefreshProps = {
  enabled: boolean;
  intervalMs?: number;
};

export function EnrichmentPendingRefresh({
  enabled,
  intervalMs = 2000
}: EnrichmentPendingRefreshProps) {
  const router = useRouter();

  useEffect(() => {
    if (!enabled) {
      return;
    }

    const intervalId = window.setInterval(() => {
      router.refresh();
    }, intervalMs);

    return () => {
      window.clearInterval(intervalId);
    };
  }, [enabled, intervalMs, router]);

  return null;
}

import Link from "next/link";

import { EnrichmentPendingRefresh } from "@/features/enrichment/components/pending-refresh";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import { listOwnerTags, listOwnerContentByTag } from "@/features/tags/service";
import { normalizeSingleTagName } from "@/features/tags/normalize";
import { requireOwnerSession } from "@/lib/auth/owner-session";

type TagsPageProps = {
  searchParams?: Promise<{
    tag?: string;
  }>;
};

export default async function TagsPage({ searchParams }: TagsPageProps) {
  const owner = await requireOwnerSession();
  const resolvedSearchParams = (await searchParams) ?? {};
  const selectedTag = normalizeSingleTagName(resolvedSearchParams.tag);
  const [tags, filteredContent] = await Promise.all([
    listOwnerTags(owner.id),
    listOwnerContentByTag(owner.id, selectedTag)
  ]);
  const hasPendingResults =
    filteredContent.notes.some((note) => note.enrichment.status === "pending") ||
    filteredContent.links.some((link) => link.enrichment.status === "pending");

  return (
    <div className="feature-layout">
      <EnrichmentPendingRefresh enabled={hasPendingResults} />
      <section className="hero-card">
        <p className="eyebrow">Shared tags</p>
        <h1>Filter the private vault by tag.</h1>
        <p className="lede">
          Shared tags stay owner-only in v1. Pick a tag to narrow private notes and saved links without exposing
          retrieval on the public site.
        </p>
        <div className="summary-row">
          <div>
            <strong>Tag library</strong>
            <span>{tags.length} shared tag{tags.length === 1 ? "" : "s"}</span>
          </div>
          <div>
            <strong>Selection</strong>
            <span>{selectedTag ?? "All private content"}</span>
          </div>
          <div>
            <strong>Public boundary</strong>
            <span>Tag exploration stays inside the owner area</span>
          </div>
        </div>
      </section>

      <section className="panel-card">
        <div className="section-heading">
          <strong>Tag filters</strong>
          <span className="section-meta">Shared across notes and links</span>
        </div>
        <div className="tag-filter-list" aria-label="Shared tag filters">
          <Link className={!selectedTag ? "tag-filter-link tag-filter-link-active" : "tag-filter-link"} href="/app/tags">
            All content
          </Link>
          {tags.length === 0 ? (
            <span className="tag-pill tag-pill-muted">No shared tags yet</span>
          ) : (
            tags.map((tag) => (
              <Link
                className={selectedTag === tag.name ? "tag-filter-link tag-filter-link-active" : "tag-filter-link"}
                href={`/app/tags?tag=${encodeURIComponent(tag.name)}`}
                key={tag.id}
              >
                {tag.name}
                <span className="tag-filter-count">
                  {tag.noteCount} note{tag.noteCount === 1 ? "" : "s"} / {tag.linkCount} link{tag.linkCount === 1 ? "" : "s"}
                </span>
              </Link>
            ))
          )}
        </div>
      </section>

      <div className="retrieval-grid">
        <section className="panel-card">
          <div className="section-heading">
            <strong>{selectedTag ? `Notes tagged ${selectedTag}` : "Private notes"}</strong>
            <span className="section-meta">Markdown drafts and published notes</span>
          </div>
          {filteredContent.notes.length === 0 ? (
            <p>{selectedTag ? "No private notes match this tag yet." : "No private notes yet."}</p>
          ) : (
            <div className="note-list">
                {filteredContent.notes.map((note) => (
                  <article className="note-list-item" key={note.id}>
                    <div>
                      <div className="note-meta note-meta-leading">
                        <span>{note.isPublished ? "Published" : "Draft"}</span>
                        <span>{new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(note.updatedAt)}</span>
                      </div>
                      <Link className="note-list-link" href={`/app/notes/${note.id}/edit`}>
                        {note.title}
                      </Link>
                      <p>{note.excerpt || "Empty draft"}</p>
                      {note.summary ? <p className="note-generated-summary">AI summary: {note.summary}</p> : null}
                      <EnrichmentStatusBlock state={note.enrichment} />
                      <div className="tag-list" aria-label="Note tags">
                        {note.tags.length === 0 ? (
                          <span className="tag-pill tag-pill-muted">Untagged</span>
                      ) : (
                        note.tags.map((tag) => (
                          <span className="tag-pill" key={tag.id}>
                            {tag.name}
                          </span>
                        ))
                      )}
                    </div>
                  </div>
                </article>
              ))}
            </div>
          )}
        </section>

        <section className="panel-card">
          <div className="section-heading">
            <strong>{selectedTag ? `Links tagged ${selectedTag}` : "Private links"}</strong>
            <span className="section-meta">Owner-only saved references</span>
          </div>
          {filteredContent.links.length === 0 ? (
            <p>{selectedTag ? "No private links match this tag yet." : "No private links yet."}</p>
          ) : (
            <div className="link-list">
                {filteredContent.links.map((link) => (
                  <article className="link-list-item" key={link.id}>
                    <div className="link-list-heading">
                      <div className="note-meta note-meta-leading">
                        <span>Private link</span>
                      </div>
                      <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                        {link.title}
                      </a>
                      <p className="link-url">{link.url}</p>
                    </div>
                    {link.summary ? <p className="link-summary">AI summary: {link.summary}</p> : null}
                    <EnrichmentStatusBlock state={link.enrichment} />
                    <div className="link-list-footer">
                      <div className="tag-list" aria-label="Link tags">
                        {link.tags.length === 0 ? (
                        <span className="tag-pill tag-pill-muted">No generated tags yet</span>
                      ) : (
                        link.tags.map((tag) => (
                          <span className="tag-pill" key={tag.id}>
                            {tag.name}
                          </span>
                        ))
                      )}
                    </div>
                    <div className="note-meta">
                      <span>Updated</span>
                        <span>{new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(link.updatedAt)}</span>
                      </div>
                    </div>
                  </article>
                ))}
              </div>
          )}
        </section>
      </div>
    </div>
  );
}

import { createLinkAction, retryLinkEnrichmentAction } from "@/app/app/links/actions";
import { EnrichmentPendingRefresh } from "@/features/enrichment/components/pending-refresh";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import { listOwnerLinks } from "@/features/links/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

type LinksPageProps = {
  searchParams?: Promise<{
    saved?: string;
    retried?: string;
    error?: string;
  }>;
};

function getStatusMessage(error?: string) {
  switch (error) {
    case "duplicate-url":
      return "That URL is already saved in your private links.";
    case "invalid-url":
      return "Enter a complete http:// or https:// URL.";
    case "missing-title":
      return "Enter a title for the saved link.";
    default:
      return undefined;
  }
}

export default async function LinksPage({ searchParams }: LinksPageProps) {
  const owner = await requireOwnerSession();
  const resolvedSearchParams = (await searchParams) ?? {};
  const links = await listOwnerLinks(owner.id);
  const pendingLinks = links.filter((link) => link.enrichment.status === "pending").length;
  const statusMessage =
    resolvedSearchParams.saved === "1"
      ? "Link saved."
      : resolvedSearchParams.retried === "1"
        ? "Retry requested."
        : getStatusMessage(resolvedSearchParams.error);

  return (
    <div className="feature-layout">
      <EnrichmentPendingRefresh enabled={links.some((link) => link.enrichment.status === "pending")} />
      <section className="hero-card">
        <p className="eyebrow">Private links</p>
        <h1>Save links for later retrieval.</h1>
        <p className="lede">
          Manual bookmark capture stays private in v1. Save the URL and title first, then let Minakeep generate the AI
          summary and shared tags after save.
        </p>
        <div className="summary-row">
          <div>
            <strong>Saved links</strong>
            <span>{links.length} private reference{links.length === 1 ? "" : "s"}</span>
          </div>
          <div>
            <strong>AI queue</strong>
            <span>{pendingLinks === 0 ? "No pending enrichment" : `${pendingLinks} link${pendingLinks === 1 ? "" : "s"} pending`}</span>
          </div>
          <div>
            <strong>Visibility</strong>
            <span>Links remain private even when notes can be published</span>
          </div>
        </div>
        {statusMessage ? (
          <p className={resolvedSearchParams.error ? "status-note status-note-error" : "status-note"}>{statusMessage}</p>
        ) : null}
      </section>

      <div className="link-manager-grid">
        <form action={createLinkAction} className="panel-card link-form">
          <div className="section-heading">
            <strong>Capture a link</strong>
            <span className="section-meta">Manual URL and title</span>
          </div>
          <label className="field-group">
            <span>URL</span>
            <input
              autoComplete="url"
              className="text-input"
              name="url"
              placeholder="https://example.com/article"
              required
              type="url"
            />
          </label>
          <label className="field-group">
            <span>Title</span>
            <input
              autoComplete="off"
              className="text-input"
              name="title"
              placeholder="Reference title"
              required
              type="text"
            />
          </label>
          <p className="field-note">AI summary and shared tags are generated automatically after save.</p>
          <div className="button-row">
            <button className="primary-button" type="submit">
              Save link
            </button>
          </div>
        </form>

        <section className="panel-card link-list-panel">
          <div className="section-heading">
            <strong>Saved links</strong>
            <span className="section-meta">Generated metadata stays secondary</span>
          </div>
          {links.length === 0 ? (
            <p>No saved links yet. Capture the first private bookmark from this page.</p>
          ) : (
            <div className="link-list">
              {links.map((link) => (
                <article className="link-list-item" key={link.id}>
                  <div className="link-list-heading">
                    <div className="note-meta note-meta-leading">
                      <span>Private link</span>
                    </div>
                    <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                      {link.title}
                    </a>
                    <p className="link-url">{link.url}</p>
                  </div>
                  <EnrichmentStatusBlock state={link.enrichment} />
                  <div className="note-generated-copy">
                    <strong>AI summary</strong>
                    {link.summary ? (
                      <p className="link-summary" data-testid="link-ai-summary">
                        {link.summary}
                      </p>
                    ) : (
                      <p className="field-note">A generated summary will appear here after a successful enrichment run.</p>
                    )}
                  </div>
                  <div className="note-generated-copy">
                    <strong>AI tags</strong>
                    <div className="tag-list" aria-label="Link tags" data-testid="link-ai-tags">
                      {link.tags.length === 0 ? (
                        <span className="tag-pill tag-pill-muted">No generated tags yet</span>
                      ) : (
                        link.tags.map((tag) => (
                          <span className="tag-pill" key={tag.id}>
                            {tag.name}
                          </span>
                        ))
                      )}
                    </div>
                  </div>
                  <div className="link-list-footer">
                    <div className="note-meta">
                      <span>Updated</span>
                      <span>{new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(link.updatedAt)}</span>
                    </div>
                  </div>
                  {link.enrichment.status === "failed" ? (
                    <form action={retryLinkEnrichmentAction.bind(null, link.id)}>
                      <button className="ghost-button" type="submit">
                        Retry AI enrichment
                      </button>
                    </form>
                  ) : null}
                </article>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

"use client";

import Link from "next/link";
import { useState } from "react";
import { useFormStatus } from "react-dom";

import { EnrichmentPendingRefresh } from "@/features/enrichment/components/pending-refresh";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import type { EnrichmentState } from "@/features/enrichment/types";
import { getEnrichmentStatusLabel } from "@/features/enrichment/types";
import { renderMarkdownToHtml } from "@/features/notes/markdown";
import type { SavedTag } from "@/features/tags/types";

type NoteEditorProps = {
  initialTitle: string;
  initialMarkdown: string;
  action: (formData: FormData) => void | Promise<void>;
  formTitle: string;
  formDescription: string;
  submitLabel: string;
  savedNotice?: string;
  enrichment?: EnrichmentState;
  generatedSummary?: string | null;
  generatedTags?: SavedTag[];
  retryAction?: () => void | Promise<void>;
  publication?: {
    isPublished: boolean;
    publicHref: `/notes/${string}`;
    publishAction: () => void | Promise<void>;
    unpublishAction: () => void | Promise<void>;
  };
};

function SaveButton({ label }: { label: string }) {
  const { pending } = useFormStatus();

  return (
    <button className="primary-button" type="submit">
      {pending ? "Saving..." : label}
    </button>
  );
}

function PublicationButton({ idleLabel, pendingLabel }: { idleLabel: string; pendingLabel: string }) {
  const { pending } = useFormStatus();

  return (
    <button className="ghost-button" type="submit">
      {pending ? pendingLabel : idleLabel}
    </button>
  );
}

function RetryButton() {
  const { pending } = useFormStatus();

  return (
    <button className="ghost-button" type="submit">
      {pending ? "Retrying..." : "Retry AI enrichment"}
    </button>
  );
}

export function NoteEditor({
  initialTitle,
  initialMarkdown,
  action,
  formTitle,
  formDescription,
  submitLabel,
  savedNotice,
  enrichment,
  generatedSummary,
  generatedTags = [],
  retryAction,
  publication
}: NoteEditorProps) {
  const [title, setTitle] = useState(initialTitle);
  const [markdown, setMarkdown] = useState(initialMarkdown);
  const previewTitle = title.trim() || "Untitled note";
  const previewHtml = renderMarkdownToHtml(markdown);

  return (
    <div className="note-editor-shell">
      <EnrichmentPendingRefresh enabled={enrichment?.status === "pending"} />
      <section className="hero-card note-editor-intro">
        <p className="eyebrow">Private note authoring</p>
        <h1>{formTitle}</h1>
        <p className="lede">{formDescription}</p>
        <div className="summary-row">
          <div>
            <strong>Drafting surface</strong>
            <span>Textarea editing with live markdown preview</span>
          </div>
          <div>
            <strong>Publishing</strong>
            <span>{publication?.isPublished ? "Currently visible on public routes" : "Private until explicitly published"}</span>
          </div>
          <div>
            <strong>AI metadata</strong>
            <span>{enrichment ? getEnrichmentStatusLabel(enrichment.status) : "Available after the first save"}</span>
          </div>
        </div>
        {publication ? (
          <div className="publication-panel">
            <div className="note-meta">
              <span>{publication.isPublished ? "Published" : "Private draft"}</span>
              <span>{publication.isPublished ? "Visible on public routes" : "Hidden from public routes"}</span>
            </div>
            <div className="button-row">
              {publication.isPublished ? (
                <form action={publication.unpublishAction}>
                  <PublicationButton idleLabel="Unpublish note" pendingLabel="Unpublishing..." />
                </form>
              ) : (
                <form action={publication.publishAction}>
                  <PublicationButton idleLabel="Publish note" pendingLabel="Publishing..." />
                </form>
              )}
              {publication.isPublished ? (
                <Link className="ghost-button" href={publication.publicHref}>
                  View public note
                </Link>
              ) : null}
            </div>
          </div>
        ) : null}
        {savedNotice ? <p className="status-note">{savedNotice}</p> : null}
      </section>

      {enrichment ? (
        <section className="panel-card note-generated-panel" data-testid="note-enrichment-panel">
          <div className="section-heading">
            <strong>AI note metadata</strong>
            <span className="section-meta">Secondary to authored content</span>
          </div>
          <EnrichmentStatusBlock state={enrichment} />
          <div className="note-generated-copy">
            <strong>AI summary</strong>
            {generatedSummary ? (
              <p data-testid="note-ai-summary">{generatedSummary}</p>
            ) : (
              <p className="field-note">A generated summary will appear here after a successful enrichment run.</p>
            )}
          </div>
          <div className="note-generated-copy">
            <strong>AI tags</strong>
            <div className="tag-list" data-testid="note-ai-tags">
              {generatedTags.length === 0 ? (
                <span className="tag-pill tag-pill-muted">No generated tags yet</span>
              ) : (
                generatedTags.map((tag) => (
                  <span className="tag-pill" key={tag.id}>
                    {tag.name}
                  </span>
                ))
              )}
            </div>
          </div>
          {enrichment.status === "failed" && retryAction ? (
            <form action={retryAction}>
              <RetryButton />
            </form>
          ) : null}
        </section>
      ) : null}

      <div className="note-editor-grid">
        <form action={action} className="panel-card note-form">
          <div className="section-heading">
            <strong>Draft</strong>
            <span className="section-meta">Title and markdown body</span>
          </div>
          <label className="field-group">
            <span>Title</span>
            <input
              autoComplete="off"
              className="text-input"
              name="title"
              onChange={(event) => setTitle(event.target.value)}
              placeholder="Draft title"
              required
              type="text"
              value={title}
            />
          </label>

          <label className="field-group note-body-field">
            <span>Markdown body</span>
            <textarea
              className="note-textarea"
              name="markdown"
              onChange={(event) => setMarkdown(event.target.value)}
              placeholder={`# Start writing

Use markdown for headings, lists, links, and code.`}
              spellCheck="true"
              value={markdown}
            />
          </label>

          <div className="button-row">
            <SaveButton label={submitLabel} />
          </div>
        </form>

        <section aria-labelledby="note-preview-heading" className="panel-card note-preview-panel">
          <div className="section-heading">
            <strong>Preview</strong>
            <span className="section-meta">Rendered markdown</span>
          </div>
          <h2 id="note-preview-heading">{previewTitle}</h2>
          <div
            className="markdown-preview"
            data-testid="note-markdown-preview"
            dangerouslySetInnerHTML={{
              __html: previewHtml || "<p>Start writing to see the rendered preview.</p>"
            }}
          />
        </section>
      </div>
    </div>
  );
}

